import React from 'react';

const GoogleAuth = ({ onSuccess, onError, text = 'Continue with Google' }) => {
  const handleGoogleSignIn = async () => {
    try {
      // Load Google API
      if (!window.google) {
        const script = document.createElement('script');
        script.src = 'https://accounts.google.com/gsi/client';
        script.async = true;
        script.defer = true;
        script.onload = initializeGoogleAuth;
        document.body.appendChild(script);
      } else {
        initializeGoogleAuth();
      }
    } catch (error) {
      console.error('Google auth error:', error);
      onError?.(error);
    }
  };

  const initializeGoogleAuth = () => {
    if (!window.google) {
      console.error('Google API not loaded');
      onError?.(new Error('Google API not loaded'));
      return;
    }

    window.google.accounts.id.initialize({
      client_id: '120848837437-r3vc51je50hah2m8vknpdrsmskhc94pg.apps.googleusercontent.com',
      callback: handleCredentialResponse,
      auto_select: false,
      cancel_on_tap_outside: true
    });

    // Show the Google Sign-In popup
    window.google.accounts.id.prompt((notification) => {
      if (notification.isNotDisplayed() || notification.isSkippedMoment()) {
        // If popup is blocked or skipped, try alternative method
        handleAlternativeSignIn();
      }
    });
  };

  const handleCredentialResponse = async (response) => {
    try {
      const token = response.credential;

      // Send token to backend
      const res = await fetch('http://localhost:5000/api/auth/google', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ token })
      });

      const data = await res.json();

      if (data.success) {
        // Store token and user data
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));

        onSuccess?.(data);
      } else {
        onError?.(new Error(data.message || 'Authentication failed'));
      }
    } catch (error) {
      console.error('Backend auth error:', error);
      onError?.(error);
    }
  };

  const handleAlternativeSignIn = () => {
    // Fallback to manual sign-in if popup is blocked
    window.open('https://accounts.google.com/signin', '_blank', 'width=500,height=600');
  };

  return (
    <button
      type="button"
      onClick={handleGoogleSignIn}
      className="w-full flex items-center justify-center px-4 py-3 border border-gray-300 rounded-md shadow-sm bg-white text-sm font-medium text-gray-700 hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500 transition-colors"
    >
      <svg className="w-5 h-5 mr-2" viewBox="0 0 24 24">
        <path
          fill="#4285F4"
          d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"
        />
        <path
          fill="#34A853"
          d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"
        />
        <path
          fill="#FBBC05"
          d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"
        />
        <path
          fill="#EA4335"
          d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"
        />
      </svg>
      {text}
    </button>
  );
};

export default GoogleAuth;
